"use client";

import React from "react";
import { motion } from "framer-motion";
import { Heart, Github, Sparkles } from "lucide-react";

export function Footer() {
  return (
    <motion.footer
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      transition={{ delay: 0.5 }}
      className="mt-auto py-8 border-t border-gray-200 dark:border-gray-800"
    >
      <div className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex flex-col sm:flex-row items-center justify-between gap-4">
          {/* Brand */}
          <div className="flex items-center gap-2 text-gray-600 dark:text-gray-400">
            <Sparkles className="w-4 h-4 text-primary-500" />
            <span className="text-sm">
              VibeQuotes — Discover inspiring quotes
            </span>
          </div>

          {/* Credits */}
          <div className="flex items-center gap-4 text-sm text-gray-500 dark:text-gray-500">
            <span className="flex items-center gap-1">
              Made with <Heart className="w-3 h-3 text-red-500 fill-current" /> using Next.js
            </span>
            <span className="hidden sm:inline">•</span>
            <a
              href="https://github.com/lukePeavey/quotable"
              target="_blank"
              rel="noopener noreferrer"
              className="flex items-center gap-1 hover:text-gray-700 dark:hover:text-gray-300 transition-colors"
            >
              <Github className="w-4 h-4" />
              Quotable API
            </a>
          </div>
        </div>

        {/* Disclaimer */}
        <p className="mt-4 text-xs text-center text-gray-400 dark:text-gray-600">
          Quotes are sourced from the Quotable API. Some modern authors may not be available.
        </p>
      </div>
    </motion.footer>
  );
}
